function calculate(inputs) {
  const grossNetWorth = Math.max(0, parseFloat(inputs.grossNetWorth) || 0);
  const totalLiabilities = Math.max(0, parseFloat(inputs.totalLiabilities) || 0);
  const specificAssetExemptions = Math.max(0, parseFloat(inputs.specificAssetExemptions) || 0);
  const wealthTaxExemptionThreshold = Math.max(0, parseFloat(inputs.wealthTaxExemptionThreshold) || 0);
  const wealthTaxRateBracket1 = Math.max(0, Math.min(100, parseFloat(inputs.wealthTaxRateBracket1) || 0)) / 100;
  const wealthTaxThresholdBracket2 = Math.max(0, parseFloat(inputs.wealthTaxThresholdBracket2) || 0);
  const wealthTaxRateBracket2 = Math.max(0, Math.min(100, parseFloat(inputs.wealthTaxRateBracket2) || 0)) / 100;

  // Step 1: Calculate Net Taxable Wealth Before General Exemption
  let netTaxableWealthBeforeExemption = grossNetWorth - totalLiabilities - specificAssetExemptions;
  netTaxableWealthBeforeExemption = Math.max(0, netTaxableWealthBeforeExemption); // Ensure non-negative

  // Step 2: Calculate Net Wealth Subject to Tax (After General Exemption)
  let netTaxableWealthAfterExemption = Math.max(0, netTaxableWealthBeforeExemption - wealthTaxExemptionThreshold);

  // Step 3: Apply Tiered Wealth Tax Rates
  let estimatedAnnualWealthTax = 0;

  if (netTaxableWealthAfterExemption > 0) {
    // Calculate tax for Bracket 1
    const taxableAmountBracket1 = Math.min(netTaxableWealthAfterExemption, wealthTaxThresholdBracket2);
    estimatedAnnualWealthTax += taxableAmountBracket1 * wealthTaxRateBracket1;

    // Calculate tax for Bracket 2
    const taxableAmountBracket2 = Math.max(0, netTaxableWealthAfterExemption - wealthTaxThresholdBracket2);
    estimatedAnnualWealthTax += taxableAmountBracket2 * wealthTaxRateBracket2;
  }

  // Step 4: Calculate Net Worth After Tax
  const netWorthAfterTax = grossNetWorth - estimatedAnnualWealthTax;

  // Step 5: Calculate Effective Wealth Tax Rate
  const effectiveWealthTaxRate = netTaxableWealthBeforeExemption > 0 
    ? (estimatedAnnualWealthTax / netTaxableWealthBeforeExemption) * 100 
    : 0;

  return {
    netTaxableWealthBeforeExemption: netTaxableWealthBeforeExemption,
    netTaxableWealthAfterExemption: netTaxableWealthAfterExemption,
    estimatedAnnualWealthTax: estimatedAnnualWealthTax,
    netWorthAfterTax: netWorthAfterTax,
    effectiveWealthTaxRate: effectiveWealthTaxRate
  };
}
